const item = $input.first().json;

const errors = [];

// Helper function
function isValidEmail(email) {
  return typeof email === 'string' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

// Required fields
const requiredFields = [
  "submission_id",
  "submitted_at",
  "submitted_by_email",
  "firm_name",
  "website",
  "country_of_registration",
  "years_in_business",
  "profit_split",
  "challenge_fee",
  "support_email"
];

for (const field of requiredFields) {
  if (
    item[field] === undefined ||
    item[field] === null ||
    item[field] === ""
  ) {
    errors.push(`Missing required field: ${field}`);
  }
}

// Email validation
if (item.submitted_by_email && !isValidEmail(item.submitted_by_email)) {
  errors.push("Invalid submitted_by_email format");
}

if (item.support_email && !isValidEmail(item.support_email)) {
  errors.push("Invalid support_email format");
}

// Website validation
if (item.website && !String(item.website).startsWith("https://")) {
  errors.push("Website must start with https://");
}

// Numeric validation
if (item.years_in_business !== undefined && Number(item.years_in_business) < 0) {
  errors.push("years_in_business cannot be negative");
}

if (
  item.profit_split !== undefined &&
  (Number(item.profit_split) < 0 || Number(item.profit_split) > 100)
) {
  errors.push("profit_split must be between 0 and 100");
}

if (item.challenge_fee !== undefined && Number(item.challenge_fee) < 0) {
  errors.push("challenge_fee cannot be negative");
}

// Array validation
if (
  item.asset_classes !== undefined &&
  !Array.isArray(item.asset_classes)
) {
  errors.push("asset_classes must be an array");
}

const is_valid = errors.length === 0;

return [
  {
    json: {
      ...item,
      is_valid,
      validation_errors: errors,
      validation_status: is_valid ? "VALID" : "INVALID"
    }
  }
];

