const item = $input.first().json;

let risk_score = 0;
let risk_reasons = [];

// Rule 1: Newer firms carry more uncertainty
if (Number(item.years_in_business) < 2) {
  risk_score += 25;
  risk_reasons.push("Firm is under 2 years in business");
}

// Rule 2: Missing support contact increases operational risk
if (!item.support_email || item.support_email === "") {
  risk_score += 20;
  risk_reasons.push("Missing support email");
}

// Rule 3: Missing terms URL reduces transparency
if (!item.terms_url || item.terms_url === "") {
  risk_score += 15;
  risk_reasons.push("Missing terms URL");
}

// Rule 4: Missing refund policy reduces trust transparency
if (!item.refund_policy_url || item.refund_policy_url === "") {
  risk_score += 15;
  risk_reasons.push("Missing refund policy URL");
}

// Rule 5: Missing status page may indicate lower operational maturity
if (!item.status_page_url || item.status_page_url === "") {
  risk_score += 10;
  risk_reasons.push("Missing status page URL");
}

// Rule 6: Very high profit split can be a risk signal
if (Number(item.profit_split) > 95) {
  risk_score += 15;
  risk_reasons.push("Unusually high profit split");
}

// Rule 7: High challenge fee may increase review interest
if (Number(item.challenge_fee) > 700) {
  risk_score += 10;
  risk_reasons.push("High challenge fee");
}

// Assign risk level
let risk_level = "LOW";
if (risk_score >= 50) {
  risk_level = "HIGH";
} else if (risk_score >= 25) {
  risk_level = "MEDIUM";
}

return [
  {
    json: {
      ...item,
      risk_score,
      risk_level,
      risk_reasons
    }
  }
];

